patch:
diff --git a/drivers/hid/hid-input.c b/drivers/hid/hid-input.c
index 0b27da7..a8a3c9b 100644
--- a/drivers/hid/hid-input.c
+++ b/drivers/hid/hid-input.c
@@ -655,6 +655,12 @@ static void hidinput_configure_usage(struct hid_input *hidinput, struct hid_fiel
 				case 0x22d: map_key_clear(KEY_ZOOMIN);		break;
 				case 0x22e: map_key_clear(KEY_ZOOMOUT);		break;
 				case 0x22f: map_key_clear(KEY_ZOOMRESET);	break;
+
+				/* BTC 8193 ugly hack */
+				case 0x230: map_key(BTN_MOUSE);			break;
+				case 0x231: map_rel(REL_WHEEL);			break;
+				case 0x232: map_rel(REL_HWHEEL);		break;
+
 				case 0x233: map_key_clear(KEY_SCROLLUP);	break;
 				case 0x234: map_key_clear(KEY_SCROLLDOWN);	break;
 				case 0x238: map_rel(REL_HWHEEL);		break;
@@ -972,6 +978,18 @@ void hidinput_hid_event(struct hid_device *hid, struct hid_field *field, struct
 		return;
 	}

+	/* BTC 8193 ugly hack */
+	if (hid->vendor == 0x0518 && hid->product == 0x0002) {
+		if (usage->code == REL_HWHEEL) {
+			input_event(input, usage->type, REL_WHEEL, -value);
+			return;
+		}
+		else if (usage->code == REL_WHEEL) {
+			input_event(input, usage->type, usage->code, value);
+			return;
+		}
+	}
+
 	if ((hid->quirks & HID_QUIRK_2WHEEL_MOUSE_HACK_ON) && (usage->code == REL_WHEEL)) {
 		input_event(input, usage->type, REL_HWHEEL, value);
 		return;
diff --git a/drivers/hid/hid-input.c b/drivers/hid/hid-input.c
index 0b27da7..32e3226 100644
--- a/drivers/hid/hid-input.c
+++ b/drivers/hid/hid-input.c
@@ -655,6 +655,12 @@ static void hidinput_configure_usage(struct hid_input *hidinput, struct hid_fiel
 				case 0x22d: map_key_clear(KEY_ZOOMIN);		break;
 				case 0x22e: map_key_clear(KEY_ZOOMOUT);		break;
 				case 0x22f: map_key_clear(KEY_ZOOMRESET);	break;
+
+				/* BTC 8193 ugly hack */
+				case 0x230: map_key(BTN_MOUSE);			break;
+				case 0x231: map_rel(REL_WHEEL);			break;
+				case 0x232: map_rel(REL_HWHEEL);		break;
+
 				case 0x233: map_key_clear(KEY_SCROLLUP);	break;
 				case 0x234: map_key_clear(KEY_SCROLLDOWN);	break;
 				case 0x238: map_rel(REL_HWHEEL);		break;
@@ -972,6 +978,18 @@ void hidinput_hid_event(struct hid_device *hid, struct hid_field *field, struct
 		return;
 	}

+	/* BTC 8193 ugly hack */
+	if (hid->vendor == 0x0518 && hid->product == 0x0002) {
+		if (usage->type == EV_REL && usage->code == REL_HWHEEL) {
+			input_event(input, usage->type, REL_WHEEL, -value);
+			return;
+		}
+		else if (usage->type == EV_REL && usage->code == REL_WHEEL) {
+			input_event(input, usage->type, usage->code, value);
+			return;
+		}
+	}
+
 	if ((hid->quirks & HID_QUIRK_2WHEEL_MOUSE_HACK_ON) && (usage->code == REL_WHEEL)) {
 		input_event(input, usage->type, REL_HWHEEL, value);
 		return;
